const openPop = (componentName) => {
rootData.rootEmit(
  'rootData:change',
  {
    key: 'showPopComponent',
    value: `${componentName}Component`,
    data: {
      showPopComponent: `${componentName}Component`
    },
  });

rootData.rootEmit(
  'rootData:change',
  {
    key: 'showPop',
    value: true,
    data: {
      showPop: true
    },
  });
};
const recentMessage = () => {
rootData.rootOn('rootSocket:change', (data) => {
  console.log('收到消息了', data);
  if (data.type === 'dataSpaceItemClick') {
    // 显示lego里的弹框
    console.log('收到消息了', data);
    let names = ["环境管理对象", "公共代码"];
    let names2 = ["环境业务主题", "环境业务专题", "环境标签", "环境指标"];
    let type = ['DW', 'ADS', 'TAG', 'IDATA'];
    if (names.includes(data.data.name)) {
      openPop("sourceControlPop");
    } else if (names2.includes(data.data.name)) {
      const index = names2.indexOf(data.data.name);
      global.indicatorType = index !== -1 && index < type.length ? type[index] : 'DW';
      openPop("indicatorStructurePop");
    }
  }
});
};
// 接口函数
const getDayAdd = () => {
return new Promise((resolve, reject) => {
  http({"url":global.serviceBasePath,"method":"get","baseURL":global.serviceBaseUrl,"params":{"interfaceId":"2ee736063db07ca556e448b526b0651b","MONITORTIME":""},}).then((res) => {
     // 成功的操作
     if (res?.data?.data) {
  const data = res.data.data;
  state.allData['DATA_DAY_ADD'] = data['DATA_DAY_ADD'] || 0;
  console.log(state.allData);
}

      resolve(_.get(res, "data"));
    }).catch((error) => {
      // 失败的操作
      
      reject(error);
    });
  });
};
// 初始请求，调取接口
getDayAdd();
// 接口函数
const getAllData = () => {
return new Promise((resolve, reject) => {
  http({"url":global.serviceBasePath,"method":"get","baseURL":global.serviceBaseUrl,"params":{"interfaceId":"5f4a17b194df087c1c04e5b1355e95e1","MONITORTIME":""},}).then((res) => {
     // 成功的操作
     if (res?.data?.data) {
  const data = res.data.data;
  for (let key in state.allData) {
    // 日增量是单独的接口获取
    if (data.hasOwnProperty(key) && key !== 'DATA_DAY_ADD') {
      state.allData[key] = data[key] || 0;
    }
  }
  console.log(state.allData);
}

      resolve(_.get(res, "data"));
    }).catch((error) => {
      // 失败的操作
      
      reject(error);
    });
  });
};
// 初始请求，调取接口
getAllData();
